import{_ as d,o as s,c as i,ag as c}from"./chunks/framework.CAXxHpAX.js";const f=JSON.parse('{"title":"鸦片战争的影响：1840-1842，中国","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-41.md","filePath":"notes/note-41.md"}'),l={name:"notes/note-41.md"};function e(r,a,o,t,v,n){return s(),i("div",null,[...a[0]||(a[0]=[c('<h1 id="鸦片战争的影响-1840-1842-中国" tabindex="-1">鸦片战争的影响：1840-1842，中国 <a class="header-anchor" href="#鸦片战争的影响-1840-1842-中国" aria-label="Permalink to &quot;鸦片战争的影响：1840-1842，中国&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">鸦片战争的影响：</span>1840-1842，中国丧失了完整独立的主权，开始沦为半殖民地半封建社会。是中国近代史的开端。自然经济遭到破坏。刺激一些官员开始了解国际形势。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">第二次鸦片战争影响：</span>1856-1860，半殖民地化程度进一步加深，西方侵略势力由沿海深入长江中下游地区，俄国占领北方大片领土。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">甲午中日战争：</span>1894-1895，侵略势力进一步深入中国腹地，大大加深了中国半殖民地化程度，刺激列强嫌弃瓜分中国狂潮，进一步加剧民族危机。及其中华民族觉醒，推动中国人民展开救亡图存斗争（百日维新、实业救国）</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">八国联军侵华：</span>清政府沦为帝国主义列强统治中国的工具；中国完全陷入半殖民地半封建社会。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、中共诞生的意义：</span>是中国历史上开天辟地的大事变，自从有了中国共产党，中国革命面貌就焕然一新。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、南昌起义的意义：</span>打响了武装反抗国民党反动派的第一枪，标志着中共独立领导革命战争、创建人民军队和武装夺取政权的开端。</p></div><div class="circle-overlay"></div></div></div>',7)])])}const _=d(l,[["render",e]]);export{f as __pageData,_ as default};
